#include<bits/stdc++.h>
using namespace std;
priority_queue<int,vector<int>,greater<int> > q;
int n,ans=0;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        int k;
        cin>>k;
        q.push(k);
    }
    for(int i=n+1;i<=2*n-1;i++)
    {
        int lch=q.top();
        q.pop();
        int rch=q.top();
        q.pop();
        int tmp=lch+rch;
        q.push(tmp);
        ans+=tmp;
    }
    cout<<ans;
    return 0;
}
